    private AppointmentModel Model { get; set; } = new();
    private bool showStep2;
    private bool isConfirmed;
    private List<string> doctors = new();
    private List<string> timeSlots = new();
    private Dictionary<string, string> serverErrors = new();
    private EditContext? editContext;

    protected override async Task OnInitializedAsync()
    {
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        // Validate step 1 fields manually
        editContext ??= new EditContext(Model);

        var step1Valid = !string.IsNullOrWhiteSpace(Model.PatientName)
            && !string.IsNullOrWhiteSpace(Model.Email)
            && IsValidEmail(Model.Email)
            && !string.IsNullOrWhiteSpace(Model.Phone)
            && !string.IsNullOrWhiteSpace(Model.InsuranceProvider);

        if (step1Valid)
        {
            showStep2 = true;
        }
        else
        {
            // Trigger validation display by submitting through EditContext
            editContext = new EditContext(Model);
            editContext.Validate();
        }
    }

    private async Task OnDoctorOrDateChanged()
    {
        if (!string.IsNullOrWhiteSpace(Model.Doctor) && Model.AppointmentDate.HasValue)
        {
            timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                Model.Doctor, Model.AppointmentDate.Value);
        }
    }

    private async Task CheckAvailability()
    {
        serverErrors.Clear();

        // Validate step 2 fields
        bool step2Valid = !string.IsNullOrWhiteSpace(Model.Doctor)
            && Model.AppointmentDate.HasValue
            && Model.AppointmentDate.Value > DateTime.Today
            && !string.IsNullOrWhiteSpace(Model.TimeSlot)
            && !string.IsNullOrWhiteSpace(Model.ReasonForVisit)
            && Model.ReasonForVisit.Length <= 500;

        if (!step2Valid)
        {
            // Let DataAnnotationsValidator handle display
            editContext = new EditContext(Model);
            editContext.Validate();
            return;
        }

        // Server-side validation
        var errors = await AppointmentService.ValidatePatientAsync(
            Model.Email,
            Model.InsuranceProvider,
            Model.Doctor,
            Model.TimeSlot);

        if (errors.Count > 0)
        {
            serverErrors = errors;
            return;
        }

        // All good — confirm
        isConfirmed = true;
    }

    private void BackToStep1()
    {
        showStep2 = false;
        serverErrors.Clear();
    }

    private void HandleSubmit()
    {
        // Form submission handled by CheckAvailability
    }

    private static bool IsValidEmail(string email)
    {
        try
        {
            var addr = new System.Net.Mail.MailAddress(email);
            return addr.Address == email;
        }
        catch
        {
            return false;
        }
    }
}
"}

{"path": "/tmp/sv-95ec435ac484436ca7dc1ac2e53f8d3b/Components/Pages/BookAppointment.Model.cs", "file_text": "using System.ComponentModel.DataAnnotations;

namespace sv_95ec435ac484436ca7dc1ac2e53f8d3b.Components.Pages;

public class AppointmentModel
{
    // Step 1
    [Required(ErrorMessage = "Patient name is required")]
    public string PatientName { get; set; } = "";

    [Required(ErrorMessage = "Email is required")]
    [EmailAddress(ErrorMessage = "Invalid email format")]
    public string Email { get; set; } = "";

    [Required(ErrorMessage = "Phone is required")]
    public string Phone { get; set; } = "";

    [Required(ErrorMessage = "Insurance provider is required")]
    public string InsuranceProvider { get; set; } = "";

    // Step 2
    [Required(ErrorMessage = "Please select a doctor")]
    public string Doctor { get; set; } = "";

    [Required(ErrorMessage = "Date is required")]
    [FutureDate(ErrorMessage = "Date must be in the future")]
    public DateTime? AppointmentDate { get; set; }

    [Required(ErrorMessage = "Please select a time slot")]
    public string TimeSlot { get; set; } = "";

    [Required(ErrorMessage = "Reason for visit is required")]
    [MaxLength(500, ErrorMessage = "Reason must be 500 characters or less")]
    public string ReasonForVisit { get; set; } = "";
}

public class FutureDateAttribute : ValidationAttribute
{
    public override bool IsValid(object? value)
    {
        if (value is DateTime date)
        {
            return date > DateTime.Today;
        }
        return false;
    }
}
"}

